import{_ as e,o as t,c as r,a3 as p}from"./chunks/framework.q4B3G9ZH.js";const d=JSON.parse('{"title":"IPV6","description":"","frontmatter":{},"headers":[],"relativePath":"服务器/IPV6.md","filePath":"服务器/IPV6.md","lastUpdated":null}'),i={name:"服务器/IPV6.md"};function s(o,a,n,c,l,m){return t(),r("div",null,[...a[0]||(a[0]=[p('<h1 id="ipv6" tabindex="-1">IPV6 <a class="header-anchor" href="#ipv6" aria-label="Permalink to &quot;IPV6&quot;">​</a></h1><h2 id="公网地址和局域网地址" tabindex="-1">公网地址和局域网地址 <a class="header-anchor" href="#公网地址和局域网地址" aria-label="Permalink to &quot;公网地址和局域网地址&quot;">​</a></h2><p><img src="https://raw.githubusercontent.com/xumyuan/image/master/img/IPV6_1.png" alt=""></p><p>2或者3开头的就是公网地址，fe，fd开头的一般是局域网地址</p><h2 id="光猫改桥接" tabindex="-1">光猫改桥接 <a class="header-anchor" href="#光猫改桥接" aria-label="Permalink to &quot;光猫改桥接&quot;">​</a></h2><p>原理就是将光猫作为一个简单的光电转换设备</p><p>路由器来构成一个子网</p><p><img src="https://raw.githubusercontent.com/xumyuan/image/master/img/IPV6_2.png" alt=""></p><p>最重要的是找运营商要到超级管理员的账户和密码</p><h3 id="主要的操作步骤" tabindex="-1">主要的操作步骤 <a class="header-anchor" href="#主要的操作步骤" aria-label="Permalink to &quot;主要的操作步骤&quot;">​</a></h3><p><img src="https://raw.githubusercontent.com/xumyuan/image/master/img/IPV6_3.png" alt=""></p><p>1.模式改成桥接</p><p>2.ip协议选择 ipv4和ipv6</p><p>3.进入路由器界面上网方式改成pppoe</p><p><img src="https://raw.githubusercontent.com/xumyuan/image/master/img/IPV6_4.png" alt=""></p><p>填写宽带拨号的账号密码，<strong>如果有防火墙就关掉</strong></p><h3 id="ddns" tabindex="-1">DDNS <a class="header-anchor" href="#ddns" aria-label="Permalink to &quot;DDNS&quot;">​</a></h3><p>运营商分配的地址会动态的变动，可以将变动的ip地址绑定到域名来访问</p><p><a href="https://github.com/jeessy2/ddns-go" target="_blank" rel="noreferrer">https://github.com/jeessy2/ddns-go</a></p><p>这个项目可以自动获得公网的ipv4/6地址 并解析到域名</p><p>可以去cloudflare购买域名</p><h3 id="网络安全" tabindex="-1">网络安全 <a class="header-anchor" href="#网络安全" aria-label="Permalink to &quot;网络安全&quot;">​</a></h3><p>ipv6几乎不可能被扫描攻击，可能的危险是访问网站下载东西的时候暴露了自己的ipv6公网ip</p><p>tips：</p><p>区分哪些设备只用来访问</p><p>哪些只提供服务</p><p><img src="https://raw.githubusercontent.com/xumyuan/image/master/img/IPV6_5.png" alt=""></p><p>nas使用强密码</p><p>参考视频</p><p><a href="https://www.bilibili.com/video/BV1jiUrYgEMY/?spm_id_from=333.337.search-card.all.click&amp;vd_source=4314c1758b3417ac7877b2ff1a4d4c98" target="_blank" rel="noreferrer">https://www.bilibili.com/video/BV1jiUrYgEMY/?spm_id_from=333.337.search-card.all.click&amp;vd_source=4314c1758b3417ac7877b2ff1a4d4c98</a></p>',30)])])}const u=e(i,[["render",s]]);export{d as __pageData,u as default};
